import React, { createContext, useState } from "react";
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import Skills from "./components/Skills";
import Projects from "./components/Projects";
import Certifications from "./components/Certifications";
import Contact from "./components/Contact";
import Modal from "./components/Modal";

export const ModalContext = createContext({ showModal: () => {} });

function App() {
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState("");
  const [modalBody, setModalBody] = useState(null);
  const [hoveredSection, setHoveredSection] = useState(null);

  const showModal = (title, body) => {
    setModalTitle(title);
    setModalBody(body);
    setModalOpen(true);
  };

  const closeModal = () => {
    setModalOpen(false);
    setHoveredSection(null);
  };

  const handleSectionHover = (sectionName, component) => {
    setHoveredSection(sectionName);
    showModal(sectionName, component);
  };

  const handleSectionLeave = () => {
    closeModal();
  };

  return (
    <ModalContext.Provider value={{ showModal }}>
      <div>
        <Navbar />
        <main>
          <section id="home" onMouseEnter={() => handleSectionHover("Home", <Home />)} onMouseLeave={handleSectionLeave}>
              <Home />
          </section>
          <section id="about" onMouseEnter={() => handleSectionHover("About", <About />)} onMouseLeave={handleSectionLeave}>
              <About />
          </section>
          <section id="skills" onMouseEnter={() => handleSectionHover("Skills", <Skills />)} onMouseLeave={handleSectionLeave}>
              <Skills />
          </section>
          <section id="projects" onMouseEnter={() => handleSectionHover("Projects", <Projects />)} onMouseLeave={handleSectionLeave}>
              <Projects />
          </section>
          <section id="certifications" onMouseEnter={() => handleSectionHover("Certifications", <Certifications />)} onMouseLeave={handleSectionLeave}>
              <Certifications />
          </section>
          <section id="contact" onMouseEnter={() => handleSectionHover("Contact", <Contact />)} onMouseLeave={handleSectionLeave}>
              <Contact />
          </section>
        </main>
      </div>
      <Modal open={modalOpen} onClose={closeModal} title={modalTitle}>
        {modalBody}
      </Modal>
    </ModalContext.Provider>
  );
}

export default App;
